    : n_bits_(n_bits),
      num_buckets_(n_bits <= 0 ? 1 : (1U << n_bits)),
      registers_(num_buckets_, 0),
      cardinality_(0) {}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  return std::bitset<BITSET_CAPACITY>(hash);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Find the position of the leftmost 1 bit (0-indexed from the right)
  // We need to find the position of the first 1 bit from the left
  for (uint64_t i = BITSET_CAPACITY; i > 0; --i) {
    if (bset[i - 1]) {
      return i;
    }
  }
  return 0;  // All zeros
}

template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ <= 0) {
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  // Calculate hash of the element
  hash_t hash = CalculateHash(val);

  // Extract the first n_bits to determine bucket index
  uint32_t bucket_idx = hash & ((1U << n_bits_) - 1);

  // Shift hash right by n_bits to get the remaining bits
  hash_t remaining_bits = hash >> n_bits_;

  // Compute binary representation of remaining bits
  std::bitset<BITSET_CAPACITY> bset = ComputeBinary(remaining_bits);

  // Find position of leftmost one bit
  uint64_t position = PositionOfLeftmostOne(bset);

  // Update register with maximum position
  if (position > registers_[bucket_idx]) {
    registers_[bucket_idx] = position;
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  std::lock_guard<std::mutex> lock(mutex_);

  if (n_bits_ <= 0) {
    cardinality_ = 0;
    return;
